import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useHistory } from 'react-router';
import PropTypes from 'prop-types';
import * as actions from '../../redux/actions';
import { ViewTitle } from 'components/ViewTitle';
import { useForm, Controller } from 'react-hook-form';

import PaymentListTable from '../../components/Table/PaymentListTable';
import { Button } from '@mui/material';

const Payment = ({ title, subtitle }) => {
  const dispatch = useDispatch();
  const history = useHistory();
  const {
    control,
    formState: { errors },
    handleSubmit,
    reset,
    setValue,
  } = useForm();

  const customer = useSelector((state) => state.customer);
  const billing = useSelector((state) => state.billing);
  const project = useSelector((state) => state.project);
  const payments = useSelector((state) => state.payments);

  const [page, setPage] = useState(1);
  const [size, setSize] = useState(20);

  useEffect(() => {
    dispatch(actions.customerAll({}));
    dispatch(actions.billingAll({}));
    dispatch(actions.projectAll({}));
    dispatch(actions.paymentAll({ page, size }));
    return () => {};
  }, [page, size]);

  const renderTitle = () => <ViewTitle title={title} subtitle={subtitle} />;
  const renderAddButton = () => (
    <div>
      <Button
        variant="contained"
        color="primary"
        onClick={() => history.push('/finance/payment/add')}
      >
        Add Payment
      </Button>
    </div>
  );
  const renderTable = () => (
    <PaymentListTable
      payments={payments}
      page={page}
      setPage={setPage}
      size={size}
      setSize={setSize}
    />
  );

  return (
    <div>
      {renderTitle()}

      <div className="py-1 flex justify-end">{renderAddButton()}</div>
      <div>{renderTable()}</div>
    </div>
  );
};

export default Payment;
